// ===== ASYNCHRONOUS dengan Async/Await =====
// Seperti pesan makanan online: Anda bisa ngobrol sambil menunggu
async function loadData() {
  console.log('1. Mulai muat data...');
  try {
    const response = await fetch('./data.json'); // Tunggu tanpa membekukan
    const data     = await response.json();      // Parse JSON-nya
    console.log('3. Data diterima:', data);
  } catch (error) {
    console.error('Gagal memuat data:', error.message);
  }
}

console.log('2. Baris ini jalan TANPA menunggu fetch!');
loadData();
// Output: 1 → 2 → (menunggu di background) → 3

// ===== POLA HYDRATION YANG BENAR =====
// Prinsip: Fetch hanya jika LocalStorage kosong

async function initApp() {
  const stored = localStorage.getItem(STORAGE_KEY);

  if (stored) {
    // Data sudah ada di LocalStorage — langsung pakai
    articles = JSON.parse(stored);
    console.log(`Memuat ${articles.length} artikel dari LocalStorage`);
  } else {
    // LocalStorage kosong — fetch data awal dari file JSON
    console.log('LocalStorage kosong. Fetching data.json...');
    try {
      const response = await fetch('./data.json');

      if (!response.ok) {
        throw new Error(`HTTP Error: ${response.status}`);
      }

      articles = await response.json();

      // Simpan ke LocalStorage agar tidak perlu fetch lagi
      saveToStorage();
      console.log(`${articles.length} artikel berhasil dimuat dan disimpan.`);

    } catch (err) {
      console.error('Gagal fetch data.json:', err.message);
      articles = []; // Fallback: mulai kosong
    }
  }

  renderTable(); // Render setelah data siap
}

// Ganti: let articles = loadFromStorage(); renderTable();
// Dengan:
initApp(); // Panggil di akhir file

